B4DUI.HUD.Register("Main",function() local p=LocalPlayer(); if not IsValid(p) then return end; local x,y=B4DUI.ClampToSafeArea(24,ScrH()-190,360,166); draw.RoundedBox(16,x,y,360,166,B4DUI.Color("panel")); draw.RoundedBox(16,x,y,4,166,B4DUI.TeamColor(p)); draw.SimpleText(p:Nick(),"B4D.Large",x+78,y+18,B4DUI.Color("text")); draw.SimpleText(team.GetName(p:Team()) or "Citizen","B4D.Small",x+78,y+43,B4DUI.Color("muted")); draw.SimpleText(B4DUI.Money(p:getDarkRPVar("money") or 0),"B4D.Body",x+78,y+68,B4DUI.Color("money")); draw.SimpleText("Salary "..B4DUI.Money(p:getDarkRPVar("salary") or 0),"B4D.Small",x+220,y+70,B4DUI.Color("muted")); local vals={{"Health",p:Health(),p:GetMaxHealth(),B4DUI.Color("health")},{"Armor",p:Armor(),100,B4DUI.Color("armor")},{"Hunger",p:getDarkRPVar("Energy") or 100,100,B4DUI.Color("hunger")}}; for i,v in ipairs(vals) do local by=y+88+i*20; draw.SimpleText(v[1],"B4D.Tiny",x+18,by-2,B4DUI.Color("muted")); draw.RoundedBox(4,x+78,by,255,7,B4DUI.Color("panel2")); draw.RoundedBox(4,x+78,by,255*math.Clamp(v[2]/v[3],0,1),7,v[4]) end end)
